"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[78423],{2824:e=>{e.exports=JSON.parse('{"tag":{"label":"player","permalink":"/dst-api-webdocs/docs/tags/player","allTagsPath":"/dst-api-webdocs/docs/tags","count":65,"items":[{"id":"game-scripts/components/age","title":"Age","description":"Tracks and manages a player entity\'s elapsed time since spawn, including pause/resume functionality and age-based notifications.","permalink":"/dst-api-webdocs/docs/game-scripts/components/age"},{"id":"game-scripts/components/aoecharging","title":"Aoecharging","description":"Manages the state and visual feedback for a charging area-of-effect attack, synchronizing charge progress and owner tracking across networked clients.","permalink":"/dst-api-webdocs/docs/game-scripts/components/aoecharging"},{"id":"game-scripts/components/attunable","title":"Attunable","description":"Manages attunement relationships between an entity and players, supporting online/offline tracking and networked persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/attunable"},{"id":"game-scripts/components/attuner","title":"Attuner","description":"Manages attunement relationships between a player and attunable entities, tracking which entities the player is attuned to and enabling server/client-side attunement queries and transfers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/attuner"},{"id":"game-scripts/components/avengingghost","title":"Avengingghost","description":"Manages the avenging ghost state for Wendy, increasing damage over time while in ghost form if a nearby player has the \'wendy_avenging_ghost\' skill activated.","permalink":"/dst-api-webdocs/docs/game-scripts/components/avengingghost"},{"id":"game-scripts/components/builder","title":"Builder","description":"Manages crafting recipes, prototyper access, tech tree progress, and ingredient consumption for builder-type entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/builder"},{"id":"game-scripts/components/builder_replica","title":"Builder Replica","description":"Serves as the client-side replica component for the Builder, syncing crafting, recipe, and technology tree state between server and client.","permalink":"/dst-api-webdocs/docs/game-scripts/components/builder_replica"},{"id":"game-scripts/components/colourcube","title":"Colourcube","description":"Manages dynamic colour grading via colour cubes (LUTs) to reflect in-game conditions such as time of day, season, sanity, and environment (caves or overworld).","permalink":"/dst-api-webdocs/docs/game-scripts/components/colourcube"},{"id":"game-scripts/components/drownable","title":"Drownable","description":"Manages drowning and void-falling logic for entities, including damage application, item dropping, and teleportation behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/drownable"},{"id":"game-scripts/components/dsp","title":"Dsp","description":"Manages dynamic audio filtering (low-pass and high-pass) based on player season, temperature, and runtime DSP stacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dsp"},{"id":"game-scripts/components/dynamicmusic","title":"Dynamicmusic","description":"Manages adaptive background music for the player entity based on gameplay context such as location, actions, time of day, season, and nearby events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dynamicmusic"},{"id":"game-scripts/components/equippable","title":"Equippable","description":"Manages item equipping behavior, including slot assignment, unequip prevention, movement speed modifiers, dapperness, moisture, and equip/unequip callbacks for entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/equippable"},{"id":"game-scripts/components/experiencecollector","title":"Experiencecollector","description":"Periodically awards experience points to eligible characters based on in-game time.","permalink":"/dst-api-webdocs/docs/game-scripts/components/experiencecollector"},{"id":"game-scripts/components/fishingrod","title":"Fishingrod","description":"Manages the fishing mechanic for a fishing rod, including casting, nibbling, strain, and reeling interactions with a fishable entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fishingrod"},{"id":"game-scripts/components/giftreceiver","title":"Giftreceiver","description":"Manages the receiver side of gift items, tracking gift count and coordinating with gift machines.","permalink":"/dst-api-webdocs/docs/game-scripts/components/giftreceiver"},{"id":"game-scripts/components/health_replica","title":"Health Replica","description":"Manages network-synchronized health state for player entities, mirroring properties from the master-side Health component for client-side UI and logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/health_replica"},{"id":"game-scripts/components/hideandseekgame","title":"Hideandseekgame","description":"Manages the Hide and Seek minigame logic, tracking seekers, hiding spots, game state, and rewards.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hideandseekgame"},{"id":"game-scripts/components/hunger","title":"Hunger","description":"Manages hunger and starvation mechanics, including decay, damage application, and synchronization with the health component.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hunger"},{"id":"game-scripts/components/inkable","title":"Inkable","description":"Tracks and manages temporary ink status on players affected by squid attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inkable"},{"id":"game-scripts/components/inventory","title":"Inventory","description":"Manages the storage, equipping, and inventory interactions for player entities, including slot-based item management, equipment handling, and container integration.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inventory"},{"id":"game-scripts/components/linkeditemmanager","title":"Linkeditemmanager","description":"Manages persistent associations between player entities and linked items, ensuring items track their creator/owner and respond appropriately when players join or leave the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/linkeditemmanager"},{"id":"game-scripts/components/locomotor","title":"Locomotor","description":"Manages entity movement, pathfinding, and speed calculations, including walking, running, platform hopping, and speed modifier interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/locomotor"},{"id":"game-scripts/components/maprecorder","title":"Maprecorder","description":"Stores and manages recorded map data for teaching exploration progress between players.","permalink":"/dst-api-webdocs/docs/game-scripts/components/maprecorder"},{"id":"game-scripts/components/miasmawatcher","title":"MiasmaWatcher","description":"Tracks whether an entity is inside a miasma cloud and applies movement speed penalties accordingly.","permalink":"/dst-api-webdocs/docs/game-scripts/components/miasmawatcher"},{"id":"game-scripts/components/mightiness","title":"Mightiness","description":"Manages Wolfgang\'s physical transformation system based on his current mightiness level, dynamically adjusting stats, animations, sounds, and gameplay modifiers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mightiness"},{"id":"game-scripts/components/mightydumbbell","title":"Mightydumbbell","description":"Manages workout and attack interactions for strongman characters, dynamically adjusting mightiness gain rates and consumption based on current mightiness state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mightydumbbell"},{"id":"game-scripts/components/mightygym","title":"Mightygym","description":"Manages weight loading, workout state, and visual/sound feedback for the Mighty Gym structure in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mightygym"},{"id":"game-scripts/components/moisture","title":"Moisture","description":"Manages a character\'s moisture level, including precipitation absorption, drying rates, waterproofing modifiers, and state transitions like wet or soaked.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moisture"},{"id":"game-scripts/components/oar","title":"Oar","description":"Handles rowing mechanics for boats, applying directional force and managing rowing success/fail behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oar"},{"id":"game-scripts/components/plantregistryupdater","title":"Plantregistryupdater","description":"Manages plant and fertilizer discovery data for a player, syncing learned content across clients in multiplayer.","permalink":"/dst-api-webdocs/docs/game-scripts/components/plantregistryupdater"},{"id":"game-scripts/components/playeractionpicker","title":"Playeractionpicker","description":"Determines valid player actions based on context (mouse position, target, held item, and modifiers).","permalink":"/dst-api-webdocs/docs/game-scripts/components/playeractionpicker"},{"id":"game-scripts/components/playeravatardata","title":"Playeravatardata","description":"Manages player avatar data including name, skins, age, and equipment, with support for network replication and save/load operations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playeravatardata"},{"id":"game-scripts/components/playercontroller","title":"Playercontroller","description":"Manages player input, locomotion prediction, targeting, placement, and combat actions for the player entity in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playercontroller"},{"id":"game-scripts/components/playerfloater","title":"Playerfloater","description":"Manages equipping and deployment behavior for player-held floating items, such as the Cloud In A Bottle.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerfloater"},{"id":"game-scripts/components/playerhearing","title":"Playerhearing","description":"Manages dynamic audio DSP filters applied to the player based on equipped items, such as muffling hats.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerhearing"},{"id":"game-scripts/components/playerinspectable","title":"Playerinspectable","description":"Syncs player equipment and skill selections to the network for client-side rendering of character appearance.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerinspectable"},{"id":"game-scripts/components/playerlightningtarget","title":"Playerlightningtarget","description":"Determines whether and how a player entity is affected when struck by lightning, including chance calculation and strike response logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerlightningtarget"},{"id":"game-scripts/components/playermetrics","title":"Playermetrics","description":"Tracks player-related gameplay events and forwards them to the metrics system for analytics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playermetrics"},{"id":"game-scripts/components/playerprox","title":"Playerprox","description":"Monitors proximity of players to an entity and triggers callbacks when players enter or leave defined zones.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerprox"},{"id":"game-scripts/components/playerspawner","title":"Playerspawner","description":"Manages player spawning logic, including position selection, spawn protection, and migration handling in the master simulation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerspawner"},{"id":"game-scripts/components/playerspeedmult","title":"Playerspeedmult","description":"Manages non-stacking speed multipliers for players by overriding the locomotor\'s runspeed, supporting both server-authoritative and client-predicted multipliers with optional hard caps.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerspeedmult"},{"id":"game-scripts/components/playertargetindicator","title":"Playertargetindicator","description":"Tracks players who should display target indicators on screen and manages their visibility based on frustum culling and tracking eligibility.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playertargetindicator"},{"id":"game-scripts/components/playervision","title":"Playervision","description":"Manages player visual modifiers (e.g., night vision, ghost vision, nightmare vision) by controlling colour cube overrides and related events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playervision"},{"id":"game-scripts/components/playervoter","title":"Playervoter","description":"Manages player vote state and submission for shared world voting systems.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playervoter"},{"id":"game-scripts/components/possessedaxe","title":"Possessedaxe","description":"Manages the transformation and reversion logic for Lucy, a possessed axe that links to a woodcutter player and reverts to a standard axe under specific conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/possessedaxe"},{"id":"game-scripts/components/rabbitkingmanager","title":"Rabbitkingmanager","description":"Manages the Rabbit King\u2019s lifecycle, including spawning, leashing to players, state transitions (passive/aggressive/lucky), and interaction tracking via carrot-feeding or naughtiness.","permalink":"/dst-api-webdocs/docs/game-scripts/components/rabbitkingmanager"},{"id":"game-scripts/components/reader","title":"Reader","description":"Enables an entity to read books and track bookworm status and sanity penalties.","permalink":"/dst-api-webdocs/docs/game-scripts/components/reader"},{"id":"game-scripts/components/rider_replica","title":"Rider Replica","description":"Manages networked state and replicated data for a rider entity, synchronizing mount, saddle, and riding status between server and client.","permalink":"/dst-api-webdocs/docs/game-scripts/components/rider_replica"},{"id":"game-scripts/components/sanity","title":"Sanity","description":"Manages sanity value, mode (Insanity/Lunacy), and related mechanics for an entity, including dynamic rate calculation from environmental and aura sources.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanity"},{"id":"game-scripts/components/sanity_replica","title":"Sanity Replica","description":"Network-replicated component that synchronizes sanity state, mode, and related properties between server and client for player entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanity_replica"},{"id":"game-scripts/components/seamlessplayerswapper","title":"Seamlessplayerswapper","description":"Handles seamless in-game player character transitions without exiting to character select, preserving inventory, tags, and clothing while updating prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/components/seamlessplayerswapper"},{"id":"game-scripts/components/sentientaxe","title":"Sentientaxe","description":"Manages sentient behavior and speech for the Lucy (Woodie\'s axe) entity, including owner interaction, transformation alerts, and conversational triggers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sentientaxe"},{"id":"game-scripts/components/shadowcreaturespawner","title":"Shadowcreaturespawner","description":"Manages the spawning, tracking, and population control of shadow creatures (e.g., Crawling Horrors, Ocean Horrors, Terrorbeaks) for players based on sanity levels and game mode.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowcreaturespawner"},{"id":"game-scripts/components/skilltreeupdater","title":"Skilltreeupdater","description":"Manages player skill tree activation, XP progression, and network synchronization across client and server.","permalink":"/dst-api-webdocs/docs/game-scripts/components/skilltreeupdater"},{"id":"game-scripts/components/skinner","title":"Skinner","description":"Manages character skin and clothing appearance for entities, including skin type switching, clothing application, and skin synchronization between players.","permalink":"/dst-api-webdocs/docs/game-scripts/components/skinner"},{"id":"game-scripts/components/sleepingbaguser","title":"Sleepingbaguser","description":"Manages a player\'s sleeping behavior and associated stat regeneration while using a sleeping bag.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sleepingbaguser"},{"id":"game-scripts/components/spectatorcorpse","title":"Spectatorcorpse","description":"Manages camera focus behavior for a player entity when spectating from a corpse, smoothly adjusting the camera range toward the nearest living player.","permalink":"/dst-api-webdocs/docs/game-scripts/components/spectatorcorpse"},{"id":"game-scripts/components/spellbook","title":"Spellbook","description":"Manages the spell wheel UI and spell execution logic for player entities, including item lists, sound effects, and conditional access rules.","permalink":"/dst-api-webdocs/docs/game-scripts/components/spellbook"},{"id":"game-scripts/components/steeringwheeluser","title":"Steeringwheeluser","description":"Manages a character\'s interaction with a steering wheel to control boat movement, including state transitions and rudder direction updates.","permalink":"/dst-api-webdocs/docs/game-scripts/components/steeringwheeluser"},{"id":"game-scripts/components/stormwatcher","title":"Stormwatcher","description":"Tracks active storms on a player entity and synchronizes storm-related properties and speed modifiers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/stormwatcher"},{"id":"game-scripts/components/strafer","title":"Strafer","description":"Manages strafing input and facing direction for player entities during movement, integrating with locomotion and player controller systems.","permalink":"/dst-api-webdocs/docs/game-scripts/components/strafer"},{"id":"game-scripts/components/temperature","title":"Temperature","description":"Manages entity body temperature, including heating/cooling logic, insulation, moisture penalties, and health impact from extreme temperatures.","permalink":"/dst-api-webdocs/docs/game-scripts/components/temperature"},{"id":"game-scripts/components/wereness","title":"Wereness","description":"Manages the wereness meter and its dynamic behavior, including draining and state persistence for player entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wereness"},{"id":"game-scripts/brains/wilsonbrain","title":"Wilsonbrain","description":"AI brain component that defines Wilson\'s default behavior tree for combat and movement, prioritizing player-held primary input while enabling fallback automated attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wilsonbrain"},{"id":"game-scripts/components/writeable","title":"Writeable","description":"Manages the ability for entities to hold and display custom text written by players.","permalink":"/dst-api-webdocs/docs/game-scripts/components/writeable"}],"unlisted":false}}')}}]);